-- Poems batch 485
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('chuci-0','离骚','屈原','战国','楚辞','chuci','','[]','帝高阳之苗裔兮，朕皇考曰伯庸。',367,'楚辞/chuci.json','["帝高阳之苗裔兮，朕皇考曰伯庸。", "摄提贞于孟陬兮，惟庚寅吾以降。", "皇览揆余初度兮，肇锡余以嘉名：", "名余曰正则兮，字余曰灵均。", "纷吾既有此内美兮，又重之以修能。", "扈江离与辟芷兮，纫秋兰以为佩。", "汨余若将不及兮，恐年岁之不吾与。", "朝搴阰之木兰兮，夕揽洲之宿莽。", "日月忽其不淹兮，春与秋其代序。", "惟草木之零落兮，恐美人之迟暮。", "不抚壮而弃秽兮，何不改乎此度?", "乘骐骥以驰骋兮，来吾道夫先路！", "昔三后之纯粹兮，固众芳之所在。", "杂申椒与菌桂兮，岂惟纫夫蕙茝！", "彼尧、舜之耿介兮，既遵道而得路。", "何桀纣之猖披兮，夫惟捷径以窘步。", "惟夫党人之偷乐兮，路幽昧以险隘。", "岂余身之殚殃兮，恐皇舆之败绩！", "忽奔走以先后兮，及前王之踵武。", "荃不查余之中情兮，反信谗而齌怒。", "余固知謇謇之为患兮，忍而不能舍也。", "指九天以为正兮，夫惟灵修之故也。", "曰黄昏以为期兮，羌中道而改路！", "初既与余成言兮，后悔遁而有他。"]'),
('chuci-1','东皇太一','屈原','战国','楚辞','chuci','','[]','吉日兮辰良，穆将愉兮上皇',95,'楚辞/chuci.json','["吉日兮辰良，穆将愉兮上皇", "抚长剑兮玉珥，璆锵鸣兮琳琅", "瑶席兮玉瑱，盍将把兮琼芳", "蕙肴蒸兮兰藉，奠桂酒兮椒浆", "扬枹兮拊鼓，疏缓节兮安歌", "陈竽瑟兮浩倡", "灵偃蹇兮姣服，芳菲菲兮满堂", "五音纷兮繁会，君欣欣兮乐康。"]'),
('chuci-2','云中君','屈原','战国','楚辞','chuci','','[]','浴兰汤兮沐芳，华采衣兮若英',90,'楚辞/chuci.json','["浴兰汤兮沐芳，华采衣兮若英", "灵连蜷兮既留，烂昭昭兮未央", "謇将憺兮寿宫，与日月兮齐光", "龙驾兮帝服，聊翱游兮周章", "灵皇皇兮既降，猋远举兮云中", "览冀洲兮有余，横四海兮焉穷", "思夫君兮太息，极劳心兮忡忡"]'),
('chuci-3','湘君','屈原','战国','楚辞','chuci','','[]','君不行兮夷犹，蹇谁留兮中洲',245,'楚辞/chuci.json','["君不行兮夷犹，蹇谁留兮中洲", "美要眇兮宜修，沛吾乘兮桂舟", "令沅湘兮无波，使江水兮安流", "望夫君兮未来，吹参差兮谁思", "驾飞龙兮北征，邅吾道兮洞庭", "薜荔柏兮蕙绸，荪桡兮兰旌", "望涔阳兮极浦，横大江兮扬灵", "扬灵兮未极，女婵媛兮为余太息", "横流涕兮潺湲，隐思君兮陫侧", "桂棹兮兰枻，斵冰兮积雪", "采薜荔兮水中，搴芙蓉兮木末", "心不同兮媒劳，恩不甚兮轻绝", "石濑兮浅浅，飞龙兮翩翩", "交不忠兮怨长，期不信兮告余以不闲", "朝骋骛兮江皋，夕弭节兮北渚", "鸟次兮屋上，水周兮堂下", "捐余玦兮江中，遗余佩兮醴浦", "采芳洲兮杜若，将以遗兮下女", "时不可兮再得，聊逍遥兮容与。"]'),
('chuci-4','湘夫人','屈原','战国','楚辞','chuci','','[]','帝子降兮北渚，目眇眇兮愁予',256,'楚辞/chuci.json','["帝子降兮北渚，目眇眇兮愁予", "袅袅兮秋风，洞庭波兮木叶下", "登白薠兮骋望，与佳期兮夕张", "鸟何萃兮苹中，罾何为兮木上？", "沅有茝兮醴有兰，思公子兮未敢言", "荒忽兮远望，观流水兮潺湲", "麋何食兮庭中，蛟何为兮水裔", "朝驰余马兮江皋，夕济兮西澨", "闻佳人兮召余，将腾驾兮偕逝", "筑室兮水中，葺之兮荷盖", "荪壁兮紫坛，播芳椒兮成堂", "桂栋兮兰橑，辛夷楣兮药房", "罔薜荔兮为帷，擗蕙櫋兮既张", "白玉兮为镇，疏石兰兮为芳", "芷葺兮荷屋，缭之兮杜衡", "合百草兮实庭，建芳馨兮庑门", "九嶷缤兮并迎，灵之来兮如云", "捐余袂兮江中，遗余褋兮醴浦", "搴汀洲兮杜若，将以遗兮远者", "时不可兮骤得，聊逍遥兮容与！"]'),
('chuci-5','大司命','屈原','战国','楚辞','chuci','','[]','广开兮天门，纷吾乘兮玄云',177,'楚辞/chuci.json','["广开兮天门，纷吾乘兮玄云", "令飘风兮先驱，使涷雨兮洒尘", "君回翔兮以下，逾空桑兮从女", "纷总总兮九州，何寿夭兮在予", "高飞兮安翔，乘清气兮御阴阳", "吾与君兮齐速，导帝之兮九坑", "灵衣兮被被，玉佩兮陆离", "一阴兮一阳，众莫知兮余所为", "折疏麻兮瑶华，将以遗兮离居", "老冉冉兮既极，不寖近兮愈疏", "乘龙兮辚辚，高驰兮冲天", "结桂枝兮延伫，羌愈思兮愁人", "愁人兮奈何，愿若今兮无亏", "固人命兮有当，孰离合兮何为？"]'),
('chuci-6','少司命','屈原','战国','楚辞','chuci','','[]','秋兰兮麋芜，罗生兮堂下',173,'楚辞/chuci.json','["秋兰兮麋芜，罗生兮堂下", "绿叶兮素华，芳菲菲兮袭予", "夫人兮自有美子，荪何以兮愁苦", "秋兰兮青青，绿叶兮紫茎", "满堂兮美人，忽独与余兮目成", "入不言兮出不辞，乘回风兮载云旗", "悲莫悲兮生别离，乐莫乐兮新相知", "荷衣兮蕙带，儵而来兮忽而逝", "夕宿兮帝郊，君谁须兮云之际", "与女沐兮咸池，曦女发兮阳之阿", "望美人兮未来，临风怳兮浩歌", "孔盖兮翠旌，登九天兮抚彗星", "竦长剑兮拥幼艾，荪独宜兮为民正。"]'),
('chuci-7','东君','屈原','战国','楚辞','chuci','','[]','暾将出兮东方，照吾槛兮扶桑',157,'楚辞/chuci.json','["暾将出兮东方，照吾槛兮扶桑", "抚余马兮安驱，夜皎皎兮既明", "驾龙輈兮乘雷，载云旗兮委蛇", "长太息兮将上，心低徊兮顾怀", "羌声色兮娱人，观者儋兮忘归", "縆瑟兮交鼓，萧钟兮瑶簴", "鸣篪兮吹竽，思灵保兮贤姱", "翾飞兮翠曾，展诗兮会舞", "应律兮合节，灵之来兮敝日", "青云衣兮白霓裳，举长矢兮射天狼", "操余弧兮反沦降，援北斗兮酌桂浆", "撰余辔兮高驰翔，杳冥冥兮以东行。"]'),
('chuci-8','河伯','屈原','战国','楚辞','chuci','','[]','与女游兮九河，冲风起兮水扬波',122,'楚辞/chuci.json','["与女游兮九河，冲风起兮水扬波", "乘水车兮荷盖，驾两龙兮骖螭", "登昆仑兮四望，心飞扬兮浩荡", "日将暮兮怅忘归，惟极浦兮寤怀", "鱼鳞屋兮龙堂，紫贝阙兮珠宫", "灵何惟兮水中", "乘白鼋兮逐文鱼，与女游兮河之渚", "流澌纷兮将来下", "子交手兮东行，送美人兮南浦", "波滔滔兮来迎，鱼鳞鳞兮媵予。"]'),
('chuci-9','山鬼','屈原','战国','楚辞','chuci','','[]','若有人兮山之阿，被薜荔兮带女萝',205,'楚辞/chuci.json','["若有人兮山之阿，被薜荔兮带女萝", "既含睇兮又宜笑，子慕予兮善窈窕", "乘赤豹兮从文狸，辛夷车兮结桂旗", "被石兰兮带杜衡，折芬馨兮遗所思", "余处幽篁兮终不见天，路险难兮独后来", "表独立兮山之上，云容容兮而在下", "杳冥冥兮羌昼晦，东风飘兮神灵雨", "留灵修兮憺忘归，岁既晏兮孰华予", "采三秀兮于山间，石磊磊兮葛蔓蔓", "怨公子兮怅忘归，君思我兮不得闲", "山中人兮芳杜若，饮石泉兮荫松柏", "君思我兮然疑作", "雷填填兮雨冥冥，猿啾啾兮狖夜鸣", "风飒飒兮木萧萧，思公子兮徒离忧。"]'),
('chuci-10','国殇','屈原','战国','楚辞','chuci','','[]','操吴戈兮被犀甲，车错毂兮短兵接',136,'楚辞/chuci.json','["操吴戈兮被犀甲，车错毂兮短兵接", "旌蔽日兮敌若云，矢交坠兮士争先", "凌余阵兮躐余行，左骖殪兮右刃伤", "霾两轮兮絷四马，援玉枹兮击鸣鼓", "天时怼兮威灵怒，严杀尽兮弃原野", "出不入兮往不反，平原忽兮路超远", "带长剑兮挟秦弓，首身离兮心不惩", "诚既勇兮又以武，终刚强兮不可凌", "身既死兮神以灵，魂魄毅兮为鬼雄。"]'),
('chuci-11','礼魂','屈原','战国','楚辞','chuci','','[]','成礼兮会鼓，',30,'楚辞/chuci.json','["成礼兮会鼓，", "传芭兮代舞", "姱女倡兮容与", "春兰兮秋菊，", "长无绝兮终古。"]'),
('chuci-12','天问','屈原','战国','楚辞','chuci','','[]','曰：',204,'楚辞/chuci.json','["曰：", "遂古之初，谁传道之？", "上下未形，何由考之？", "冥昭瞢暗，谁能极之？", "冯翼惟象，何以识之？", "明明暗暗，惟时何为？", "阴阳三合，何本何化？", "圜则九重，孰营度之？", "惟兹何功，孰初作之？", "斡维焉系，天极焉加？", "八柱何当，东南何亏？", "九天之际，安放安属？", "隅隈多有，谁知其数？", "天何所沓？", "十二焉分？", "日月安属？", "列星安陈？", "出自汤谷，次于蒙汜。", "自明及晦，所行几里？", "夜光何德，死则又育？", "厥利维何，而顾菟在腹？", "女岐无合，夫焉取九子？", "伯强何处？", "惠气安在？"]'),
('chuci-13','惜诵','屈原','战国','楚辞','chuci','','[]','惜诵以致愍兮，发愤以抒情。',365,'楚辞/chuci.json','["惜诵以致愍兮，发愤以抒情。", "所作忠而言之兮，指苍天以为正。", "令五帝使折中兮，戒六神与向服。", "俾山川以备御兮，命咎繇使听直。", "竭忠诚而事君兮，反离群而赘肬。", "忘儇媚以背众兮，待明君其知之。", "言与行其可迹兮，情与貌其不变。", "故相臣莫若君兮，所以证之不远。", "吾谊先君而后身兮，羌众人之所仇也。", "专惟君而无他兮，又众兆之所雠也。", "壹心而不豫兮，羌无可保也。", "疾亲君而无他兮，有招祸之道也。", "思君其莫我忠兮，忽忘身之贱贫。", "事君而不贰兮，迷不知宠之门。", "患何罪以遇罚兮，亦非余之所志也。", "行不群以巅越兮，又众兆之所咍也。", "纷逢尤以离谤兮，謇不可释也。", "情沉抑而不达兮，又蔽而莫之白也。", "心郁邑余侘傺兮，又莫察余之中情。", "固烦言不可结而诒兮，愿陈志而无路。", "退静默而莫余知兮，进号呼又莫吾闻。", "申侘傺之烦惑兮，中闷瞀之忳忳。", "昔余梦登天兮，魂中道而无杭。", "吾使厉神占之兮，曰有志极而无旁。"]'),
('chuci-14','涉江','屈原','战国','楚辞','chuci','','[]','余幼好此奇服兮，年既老而不衰。',358,'楚辞/chuci.json','["余幼好此奇服兮，年既老而不衰。", "带长铗之陆离兮，冠切云之崔嵬，被明月兮佩宝璐。", "世混浊而莫余知兮，吾方高驰而不顾。", "驾青虬兮骖白螭，吾与重华游兮瑶之圃。", "登昆仑兮食玉英，与天地兮同寿，与日月兮同光。", "哀南夷之莫吾知兮，旦余济乎江湘。", "乘鄂渚而反顾兮，欸秋冬之绪风。", "步余马兮山皋，邸余车兮方林。", "乘舲船余上沅兮，齐吴榜以击汰。", "船容与而不进兮，淹回水而疑滞。", "朝发枉渚兮，夕宿辰阳。", "苟余心其端直兮，虽僻远之何伤。", "入溆浦余儃徊兮，迷不知吾所如。", "深林杳以冥冥兮，猿狖之所居。", "山峻高以蔽日兮，下幽晦以多雨。", "霰雪纷其无垠兮，云霏霏而承宇。", "哀吾生之无乐兮，幽独处乎山中。", "吾不能变心而从俗兮，固将愁苦而终穷。", "接舆髡首兮，桑扈臝行。", "忠不必用兮，贤不必以。", "伍子逢殃兮，比干菹醢。", "与前世而皆然兮，吾又何怨乎今之人！", "余将董道而不豫兮，固将重昏而终身！", "乱曰："]'),
('chuci-15','哀郢','屈原','战国','楚辞','chuci','','[]','皇天之不纯命兮，何百姓之震愆？',363,'楚辞/chuci.json','["皇天之不纯命兮，何百姓之震愆？", "民离散而相失兮，方仲春而东迁。", "去故乡而就远兮，遵江夏以流亡。", "出国门而轸怀兮，甲之鼂吾以行。", "发郢都而去闾兮，怊荒忽其焉极？", "楫齐扬以容与兮，哀见君而不再得。", "望长楸而太息兮，涕淫淫其若霰。", "过夏首而西浮兮，顾龙门而不见。", "心婵媛而伤怀兮，眇不知其所蹠。", "顺风波以从流兮，焉洋洋而为客。", "凌阳侯之汜滥兮，忽翱翔之焉薄。", "心絓结而不解兮，思蹇产而不释。", "将运舟而下浮兮，上洞庭而下江。", "去终古之所居兮，今逍遥而来东。", "羌灵魂之欲归兮，何须臾而忘反。", "背夏浦而西思兮，哀故都之日远。", "登大坟以远望兮，聊以舒吾忧心。", "哀州土之平乐兮，悲江介之遗风。", "当陵阳之焉至兮，淼南渡之焉如？", "曾不知夏之为丘兮，孰两东门之可芜？", "心不怡之长久兮，忧与愁其相接。", "惟郢路之辽远兮，江与夏之不可涉。", "忽若不信兮，至今九年而不复。", "惨郁郁而不通兮，蹇侘傺而含慼。"]'),
('chuci-16','抽思','屈原','战国','楚辞','chuci','','[]','心郁郁之忧思兮，独永叹乎增伤。',337,'楚辞/chuci.json','["心郁郁之忧思兮，独永叹乎增伤。", "思蹇产之不释兮，曼遭夜之方长。", "悲秋风之动容兮，何回极之浮浮。", "数惟荪之多怒兮，伤余心之忧忧。", "愿摇起而横奔兮，览民尤以自镇。", "结微情以陈词兮，矫以遗夫美人。", "昔君与我诚言兮，曰黄昏以为期。", "羌中道而回畔兮，反既有此他志。", "憍吾以其美好兮，览余以其修姱。", "与余言而不信兮，盖为余而造怒。", "愿承閒而自察兮，心震悼而不敢。", "悲夷犹而冀进兮，心怛伤之憺憺。", "兹历情以陈辞兮，荪详聋而不闻。", "固切人之不媚兮，众果以我为患。", "初吾所陈之耿著兮，岂至今其庸亡？", "何独乐斯之謇謇兮？", "愿荪美之可光。", "望三王以为像兮，指彭咸以为仪。", "夫何极而不至兮，故远闻而难亏。", "善不由外来兮，名不可以虚作。", "孰无施而有报兮，孰不实而有获？", "少歌曰：与美人抽思兮，并日夜而无正。", "憍吾以其美好兮，敖朕辞而不听。", "倡曰："]'),
('chuci-17','怀沙','屈原','战国','楚辞','chuci','','[]','滔滔孟夏兮，草木莽莽。',290,'楚辞/chuci.json','["滔滔孟夏兮，草木莽莽。", "伤怀永哀兮，汩徂南土。", "眴兮杳杳，孔静幽默。", "郁结纡轸兮，离慜而长鞠。", "抚情效志兮，冤屈而自抑。", "刓方以为圜兮，常度未替。", "易初本迪兮，君子所鄙。", "章画志墨兮，前图未改。", "内厚质正兮，大人所盛。", "巧倕不斲兮，孰察其拨正。", "玄文处幽兮，矇瞍谓之不章", "离娄微睇兮，瞽以为无明。", "变白以为黑兮，倒上以为下。", "凤皇在笯兮，鸡鹜翔舞。", "同糅玉石兮，一概而相量。", "夫惟党人之鄙固兮，羌不知余之所臧。", "任重载盛兮，陷滞而不济。", "怀瑾握瑜兮，穷不知所示。", "邑犬之群吠兮，吠所怪也。", "非俊疑杰兮，固庸态也。", "文质疏内兮，众不知余之异采。", "材朴委积兮，莫知余之所有。", "重仁袭义兮，谨厚以为丰。", "重华不可遌兮，孰知余之从容！"]'),
('chuci-18','思美人','屈原','战国','楚辞','chuci','','[]','思美人兮，揽涕而竚眙。',349,'楚辞/chuci.json','["思美人兮，揽涕而竚眙。", "媒绝路阻兮，言不可结而诒。", "蹇蹇之烦冤兮，陷滞而不发。", "申旦以舒中情兮，志沉菀而莫达。", "愿寄言于浮云兮，遇丰隆而不将。", "因归鸟而致辞兮，羌迅高而难当。", "高辛之灵盛兮，遭玄鸟而致诒。", "欲变节以从俗兮，媿易初而屈志。", "独历年而离愍兮，羌凭心犹未化。", "宁隐闵而寿考兮，何变易之可为！", "知前辙之不遂兮，未改此度。", "车既覆而马颠兮，蹇独怀此异路。", "勒骐骥而更驾兮，造父为我操之，", "迁逡次而勿驱兮，聊假日以须是时。", "指嶓冢之西隈兮，与纁黄以为期。", "开春发岁兮，白日出之悠悠。", "吾将荡志而愉乐兮，遵江夏以娱忧。", "揽大薄之芳茝兮，搴长洲之宿莽。", "惜吾不及古人兮，吾谁与玩此芳草？", "解萹薄与杂菜兮，备以为交佩。", "佩缤纷以缭转兮，遂萎绝而离异。", "吾且儃徊以娱忧兮，观南人之变态。", "窃快在中心兮，扬厥凭而不竢。", "芳与泽其杂糅兮，羌芳华自中出。"]'),
('chuci-19','惜往日','屈原','战国','楚辞','chuci','','[]','惜往日之曾信兮，受命诏以昭时。',362,'楚辞/chuci.json','["惜往日之曾信兮，受命诏以昭时。", "奉先功以照下兮，明法度之嫌疑。", "国富强而法立兮，属贞臣而日竢。", "秘密事之载心兮，虽过失犹弗治。", "心纯庞而不泄兮，遭谗人而嫉之。", "君含怒而待臣兮，不清澈其然否。", "蔽晦君之聪明兮，虚惑误又以欺。", "弗参验以考实兮，远迁臣而弗思。", "信谗谀之浑浊兮，盛气志而过之。", "何贞臣之无罪兮，被离谤而见尤。", "惭光景之诚信兮，身幽隐而备之。", "临沅湘之玄渊兮，遂自忍而沉流。", "卒没身而绝名兮，惜壅君之不昭。", "君无度而弗察兮，使芳草为薮幽。", "焉舒情而抽信兮，恬死亡而不聊。", "独障壅而弊隐兮，使贞臣为无由。", "闻百里之为虏兮，伊尹烹于庖厨。", "吕望屠于朝歌兮，宁戚歌而饭牛。", "不逢汤武与桓缪兮，世孰云而知之。", "吴信谗而弗味兮，子胥死而后忧。", "介子忠而立枯兮，文君寤而追求。", "封介山而为之禁兮，报大德之优游。", "思久故之亲身兮，因缟素而哭之。", "或忠信而死节兮，或訑谩而不疑。"]'),
('chuci-20','橘颂','屈原','战国','楚辞','chuci','','[]','后皇嘉树，橘徕服兮。',188,'楚辞/chuci.json','["后皇嘉树，橘徕服兮。", "受命不迁，生南国兮。", "深固难徙，更壹志兮。", "绿叶素荣，纷其可喜兮。", "曾枝剡棘，圆果抟兮。", "青黄杂糅，文章烂兮。", "精色内白，类任道兮。", "纷緼宜修，姱而不丑兮。", "嗟尔幼志，有以异兮。", "独立不迁，岂不可喜兮？", "深固难徙，廓其无求兮。", "苏世独立，横而不流兮。", "闭心自慎，终不失过兮。", "秉德无私，参天地兮。", "愿岁并谢，与长友兮。", "淑离不淫，梗其有理兮。", "年岁虽少，可师长兮。", "行比伯夷，置以为像兮。"]'),
('chuci-21','悲回风','屈原','战国','楚辞','chuci','','[]','悲回风之摇蕙兮，心冤结而内伤。',367,'楚辞/chuci.json','["悲回风之摇蕙兮，心冤结而内伤。", "物有微而陨性兮，声有隐而先倡。", "夫何彭咸之造思兮，暨志介而不忘！", "万变其情岂可盖兮，孰虚伪之可长？", "鸟兽鸣以号群兮，草苴比而不芳。", "鱼葺鳞以自别兮，蛟龙隐其文章。", "故荼荠不同亩兮，兰茝幽而独芳。", "惟佳人之永都兮，更统世以自贶。", "眇远志之所及兮，怜浮云之相羊。", "介眇志之所惑兮，窃赋诗之所明。", "惟佳人之独怀兮，折若椒以自处。", "曾歔欷之嗟嗟兮，独隐伏而思虑。", "涕泣交而凄凄兮，思不眠以至曙。", "终长夜之曼曼兮，掩此哀而不去。", "寤从容以周流兮，聊逍遥以自恃。", "伤太息之愍怜兮，气于邑而不可止。", "糺思心以为纕兮，编愁苦以为膺。", "折若木以弊光兮，随飘风之所仍。", "存彷佛而不见兮，心踊跃其若汤。", "抚珮衽以案志兮，超惘惘而遂行。", "岁曶曶其若颓兮，时亦冉冉而将至。", "薠蘅槁而节离兮，芳以歇而不比。", "怜思心之不可惩兮，证此言之不可聊。", "宁溘死而流亡兮，不忍此心之常愁。"]'),
('chuci-22','远游','屈原','战国','楚辞','chuci','','[]','悲时俗之迫阨兮，愿轻举而远游。',353,'楚辞/chuci.json','["悲时俗之迫阨兮，愿轻举而远游。", "质菲薄而无因兮，焉讬乘而上浮？", "遭沈浊而污秽兮，独郁结其谁语！", "夜耿耿而不寐兮，魂营营而至曙。", "惟天地之无穷兮，哀人生之长勤。", "往者余弗及兮，来者吾不闻。", "步徙倚而遥思兮，怊惝怳而乖怀。", "意荒忽而流荡兮，心愁悽而增悲。", "神倏忽而不反兮，形枯槁而独留。", "内惟省以操端兮，求正气之所由。", "漠虚静以恬愉兮，澹无为而自得。", "闻赤松之清尘兮，愿承风乎遗则。", "贵真人之休德兮，美往世之登仙", "与化去而不见兮，名声著而日延。", "奇傅说之讬辰星兮，羡韩众之得一。", "形穆穆以浸远兮，离人群而遁逸。", "因气变而遂曾举兮，忽神奔而鬼怪。", "时仿佛以遥见兮，精晈晈以往来。", "超氛埃而淑邮兮，终不反其故都。", "免众患而不惧兮，世莫知其所如。", "恐天时之代序兮，耀灵晔而西征。", "微霜降而下沦兮，悼芳草之先蘦。", "聊仿佯而逍遥兮，永历年而无成。", "谁可与玩斯遗芳兮？"]'),
('chuci-23','卜居','屈原','战国','楚辞','chuci','','[]','屈原既放，三年不得复见。竭知尽忠而蔽障于谗。心烦虑乱，不知所从。乃往见太卜郑詹尹曰：“余有所疑，愿因先生决之。”詹尹乃端策拂龟，曰：“君将何以教之？”',381,'楚辞/chuci.json','["屈原既放，三年不得复见。竭知尽忠而蔽障于谗。心烦虑乱，不知所从。乃往见太卜郑詹尹曰：“余有所疑，愿因先生决之。”詹尹乃端策拂龟，曰：“君将何以教之？”", "屈原曰：“吾宁悃悃款款，朴以忠乎，将送往劳来，斯无穷乎？宁诛锄草茅以力耕乎，将游大人以成名乎？宁正言不讳以危身乎，将从俗富贵以偷生乎？宁超然高举以保真乎，将哫訾栗斯，喔咿儒儿，以事妇人乎？宁廉洁正直以自清乎，将突梯滑稽，如脂如韦，以洁楹乎？宁昂昂若千里之驹乎，将泛泛若水中之凫，与波上下，偷以全吾躯乎？宁与骐骥亢轭乎，将随驽马之迹乎？宁与黄鹄比翼乎，将与鸡鹜争食乎？此孰吉孰凶？何去何从？世溷浊而不清：蝉翼为重，千钧为轻黄钟毁弃，瓦釜雷鸣谗人高张，贤士无名。吁嗟默默兮，谁知吾之廉贞！”", "詹尹乃释策而谢曰：“夫尺有所短，寸有所长物有所不足，智有所不明数有所不逮，神有所不通。用君之心，行君之意。龟策诚不能知此事。”"]'),
('chuci-24','渔父','屈原','战国','楚辞','chuci','','[]','屈原既放，游于江潭，行吟泽畔，颜色憔悴，形容枯槁。渔父见而问之曰：“子非三闾大夫与？何故至于斯？”屈原曰：“举世皆浊我独清，众人皆醉我独醒，是以见放。”',260,'楚辞/chuci.json','["屈原既放，游于江潭，行吟泽畔，颜色憔悴，形容枯槁。渔父见而问之曰：“子非三闾大夫与？何故至于斯？”屈原曰：“举世皆浊我独清，众人皆醉我独醒，是以见放。”", "渔父曰：“圣人不凝滞于物，而能与世推移。世人皆浊，何不淈其泥而扬其波？众人皆醉，何不餔其糟而歠其醨？何故深思高举，自令放为？”", "屈原曰：“吾闻之，新沐者必弹冠，新浴者必振衣安能以身之察察，受物之汶汶者乎？宁赴湘流，葬于江鱼之腹中。安能以皓皓之白，而蒙世俗之尘埃乎?”", "渔父莞尔而笑，鼓枻而去。", "乃歌曰：“沧浪之水清兮，可以濯吾缨。沧浪之水浊兮，可以濯吾足。”遂去，不复与言。"]'),
('chuci-25','九辩','宋玉','战国','楚辞','chuci','','[]','悲哉，秋之为气也！萧瑟兮草木摇落而变衰。',388,'楚辞/chuci.json','["悲哉，秋之为气也！萧瑟兮草木摇落而变衰。", "憭栗兮若在远行，登山临水兮送将归。", "泬漻兮天高而气清，寂寥兮收潦而水清。", "憯悽增欷兮，薄寒之中人，怆怳懭悢兮，去故而就新。", "坎廪兮贫士失职而志不平，廓落兮羁旅而无友生，惆怅兮而私自怜！", "燕翩翩其辞归兮，蝉寂漠而无声。", "雁廱廱而南游兮，鹍鸡啁哳而悲鸣。", "独申旦而不寐兮，哀蟋蟀之宵征。", "时亹亹而过中兮，蹇淹留而无成。", "悲忧穷戚兮独处廓，有美一人兮心不绎。", "去乡离家兮来远客，超逍遥兮今焉薄！", "专思君兮不可化，君不知兮可奈何！", "蓄怨兮积思，心烦憺兮忘食事。", "原一见兮道余意，君之心兮与余异。", "车既驾兮朅而归，不得见兮心伤悲。", "倚结軨兮长太息，涕潺湲兮下霑轼。", "忼慨绝兮不得，中瞀乱兮迷惑。", "私自怜兮何极？", "心怦怦兮谅直。", "皇天平分四时兮，窃独悲此凛秋。", "白露既下百草兮，奄离披此梧楸。", "去白日之昭昭兮，袭长夜之悠悠。", "离芳蔼之方壮兮，余萎约而悲愁。", "秋既先戒以白露兮，冬又申之以严霜。"]'),
('chuci-26','招魂','宋玉','战国','楚辞','chuci','','[]','朕幼清以廉洁兮，身服义而未沫。',365,'楚辞/chuci.json','["朕幼清以廉洁兮，身服义而未沫。", "主此盛德兮，牵于俗而芜秽。", "上无所考此盛德兮，长离殃而愁苦。", "帝告巫阳曰：“有人在下，我欲辅之。魂魄离散，汝筮予之。”", "巫阳对曰：“掌梦！上帝其难从。若必筮予之，恐后之谢，不能复用。”", "巫阳焉乃下招曰：魂兮归来！去君之恒干，何为四方些？", "舍君之乐处，而离彼不祥些！魂兮归来！东方不可以讬些。", "长人千仞，惟魂是索些。", "十日代出，流金铄石些。", "彼皆习之，魂往必释些。", "归来兮！不可以讬些。", "魂兮归来！南方不可以止些。", "雕题黑齿，得人肉以祀，以其骨为醢些。", "蝮蛇蓁蓁，封狐千里些。", "雄虺九首，往来倏忽，吞人以益其心些。", "归来兮！不可久淫些。", "魂兮归来！西方之害，流沙千里些。", "旋入雷渊，爢散而不可止些。", "幸而得脱，其外旷宇些。", "赤蚁若象，玄蜂若壶些。", "五谷不生，丛菅是食些。", "其土烂人，求水无所得些。", "彷徉无所倚，广大无所极些。", "归来兮！恐自遗贼些。"]'),
('chuci-27','大招','景差','战国','楚辞','chuci','','[]','青春受谢，白日昭只。',267,'楚辞/chuci.json','["青春受谢，白日昭只。", "春气奋发，万物遽只。", "冥凌浃行，魂无逃只。", "魂魄归来！无远遥只。", "魂乎归来！无东无西，无南无北只。", "东有大海，溺水浟浟只。", "螭龙并流，上下悠悠只。", "雾雨淫淫，白皓胶只。", "魂乎无东！汤谷寂寥只。", "魂乎无南！南有炎火千里，蝮蛇蜒只。", "山林险隘，虎豹蜿只。", "鰅鳙短狐，王虺骞只。", "魂乎无南！蜮伤躬只", "魂乎无西！西方流沙，漭洋洋只。", "豕首纵目，被发鬤只。", "长爪踞牙，诶笑狂只。", "魂乎无西！多害伤只。", "魂乎无北！北有寒山，趠龙赩只。", "代水不可涉，深不可测只。", "天白颢颢，寒凝凝只。", "魂乎无往！盈北极只。", "魂魄归来！闲以静只。", "自恣荆楚，安以定只。", "逞志究欲，心意安只。"]'),
('chuci-28','惜誓','贾谊','战国','楚辞','chuci','','[]','惜余年老而日衰兮，岁忽忽而不反。',370,'楚辞/chuci.json','["惜余年老而日衰兮，岁忽忽而不反。", "登苍天而高举兮，历众山而日远。", "观江河之纡曲兮，离四海之霑濡。", "攀北极而一息兮，吸沆瀣以充虚。", "飞朱鸟使先驱兮，驾太一之象舆。", "苍龙蚴虯于左骖兮，白虎骋而为右騑。", "建日月以为盖兮，载玉女于後车。", "驰骛于杳冥之中兮，休息虖昆仑之墟。", "乐穷极而不厌兮，愿从容虖神明。", "涉丹水而驰骋兮，右大夏之遗风。", "黄鹄之一举兮，知山川之纡曲。", "再举兮，睹天地之圜方。", "临中国之众人兮，讬回飙乎尚羊。", "乃至少原之野兮，赤松、王乔皆在旁。", "二子拥瑟而调均兮，余因称乎清商。", "澹然而自乐兮，吸众气而翱翔。", "念我长生而久仙兮，不如反余之故乡。", "黄鹄後时而寄处兮，鸱枭群而制之。", "神龙失水而陆居兮，为蝼蚁之所裁。", "夫黄鹄神龙犹如此兮，况贤者之逢乱世哉。", "寿冉冉而日衰兮，固儃回而不息。", "俗流从而不止兮，众枉聚而矫直。", "或偷合而苟进兮，或隐居而深藏。", "苦称量之不审兮，同权概而就衡。"]'),
('chuci-29','招隐士','淮南小山','战国','楚辞','chuci','','[]','桂树丛生兮山之幽，偃蹇连蜷兮枝相缭。',227,'楚辞/chuci.json','["桂树丛生兮山之幽，偃蹇连蜷兮枝相缭。", "山气巄嵷兮石嵯峨，溪谷崭岩兮水曾波。", "猿狖群啸兮虎豹嗥，攀援桂枝兮聊淹留。", "王孙游兮不归，春草生兮萋萋。", "岁暮兮不自聊，蟪蛄鸣兮啾啾。", "坱兮轧，山曲岪，心淹留兮恫慌忽。", "罔兮沕，憭兮栗，虎豹穴。", "丛薄深林兮，人上栗。", "嵚岑碕礒兮，碅磳磈硊", "树轮相纠兮，林木茷骫。", "青莎杂树兮，薠草靃靡", "白鹿麏麚兮，或腾或倚。", "状貌崟崟兮峨峨，凄凄兮漇漇。", "猕猴兮熊罴，慕类兮以悲", "攀援桂枝兮聊淹留。", "虎豹斗兮熊罴咆，禽兽骇兮亡其曹。", "王孙兮归来，山中兮不可以久留。"]'),
('chuci-30','初放','东方朔','战国','楚辞','chuci','','[]','平生于国兮，长于原野。',250,'楚辞/chuci.json','["平生于国兮，长于原野。", "言语讷譅兮，又无彊辅。", "浅智褊能兮，闻见又寡。", "数言便事兮，见怨门下。", "王不察其长利兮，卒见弃乎原野。", "伏念思过兮，无可改者。", "群众成朋兮，上浸以惑。", "巧佞在前兮，贤者灭息。", "尧、舜圣已没兮，孰为忠直？", "高山崔巍兮，水流汤汤。", "死日将至兮，与麋鹿同坑。", "塊兮鞠，当道宿，举世皆然兮，余将谁告？", "斥逐鸿鹄兮，近习鸱枭，斩伐橘柚兮，列树苦桃。", "便娟之修竹兮，寄生乎江潭。", "上葳蕤而防露兮，下泠泠而来风。", "孰知其不合兮，若竹柏之异心。", "往者不可及兮，来者不可待。", "悠悠苍天兮，莫我振理。", "窃怨君之不寤兮，吾独死而後已。"]'),
('chuci-31','沉江','东方朔','战国','楚辞','chuci','','[]','惟往古之得失兮，览私微之所伤。',361,'楚辞/chuci.json','["惟往古之得失兮，览私微之所伤。", "尧舜圣而慈仁兮，後世称而弗忘。", "齐桓失于专任兮，夷吾忠而名彰。", "晋献惑于孋姬兮，申生孝而被殃。", "偃王行其仁义兮，荆文寤而徐亡。", "纣暴虐以失位兮，周得佐乎吕望。", "修往古以行恩兮，封比干之丘垄。", "贤俊慕而自附兮，日浸淫而合同。", "明法令而修理兮，兰芷幽而有芳。", "苦众人之妒予兮，箕子寤而佯狂。", "不顾地以贪名兮，心怫郁而内伤。", "联蕙芷以为佩兮，过鲍肆而失香。", "正臣端其操行兮，反离谤而见攘。", "世俗更而变化兮，伯夷饿于首阳。", "独廉洁而不容兮，叔齐久而逾明。", "浮云陈而蔽晦兮，使日月乎无光。", "忠臣贞而欲谏兮，谗谀毁而在旁。", "秋草荣其将实兮，微霜下而夜降。", "商风肃而害生兮，百草育而不长。", "众并谐以妒贤兮，孤圣特而易伤。", "怀计谋而不见用兮，岩穴处而隐藏。", "成功隳而不卒兮，子胥死而不葬。", "世从俗而变化兮，随风靡而成行。", "信直退而毁败兮，虚伪进而得当。"]'),
('chuci-32','怨世','东方朔','战国','楚辞','chuci','','[]','世沉淖而难论兮，俗岒峨而嵾嵯。',383,'楚辞/chuci.json','["世沉淖而难论兮，俗岒峨而嵾嵯。", "清泠泠而歼灭兮，溷湛湛而日多。", "枭鸮既以成群兮，玄鹤弭翼而屏移。", "蓬艾亲入御于床笫兮，马兰踸踔而日加。", "弃捐药芷与杜衡兮，余柰世之不知芳何？", "何周道之平易兮，然芜秽而险戏。", "高阳无故而委尘兮，唐虞点灼而毁议。", "谁使正其真是兮，虽有八师而不可为。", "皇天保其高兮，后土持其久。", "服清白以逍遥兮，偏与乎玄英异色。", "西施媞媞而不得见兮，嫫母勃屑而日侍。", "桂蠹不知所淹留兮，蓼虫不知徙乎葵菜。", "处湣湣之浊世兮，今安所达乎吾志。", "意有所载而远逝兮，固非众人之所识。", "骥踌躇于弊輂兮，遇孙阳而得代。", "吕望穷困而不聊生兮，遭周文而舒志。", "宁戚饭牛而商歌兮，桓公闻而弗置。", "路室女之方桑兮，孔子过之以自侍。", "吾独乖剌而无当兮，心悼怵而耄思。", "思比干之恲恲兮，哀子胥之慎事。", "悲楚人之和氏兮，献宝玉以为石。", "遇厉武之不察兮，羌两足以毕斮。", "小人之居势兮，视忠正之何若？", "改前圣之法度兮，喜嗫嚅而妄作。"]'),
('chuci-33','怨思','东方朔','战国','楚辞','chuci','','[]','贤士穷而隐处兮，廉方正而不容。',122,'楚辞/chuci.json','["贤士穷而隐处兮，廉方正而不容。", "子胥谏而靡躯兮，比干忠而剖心。", "子推自割而飤君兮，德日忘而怨深。", "行明白而曰黑兮，荆棘聚而成林。", "江离弃于穷巷兮，蒺藜蔓乎东厢。", "贤者蔽而不见兮，谗谀进而相朋。", "枭鸮并进而俱鸣兮，凤皇飞而高翔。", "原壹往而径逝兮，道壅绝而不通。"]'),
('chuci-34','自悲','东方朔','战国','楚辞','chuci','','[]','居愁懃其谁告兮，独永思而忧悲。',372,'楚辞/chuci.json','["居愁懃其谁告兮，独永思而忧悲。", "内自省而不惭兮，操愈坚而不衰。", "隐三年而无决兮，岁忽忽其若颓。", "怜余身不足以卒意兮，冀一见而复归。", "哀人事之不幸兮，属天命而委之咸池。", "身被疾而不闲兮，心沸热其若汤。", "冰炭不可以相并兮，吾固知乎命之不长。", "哀独苦死之无乐兮，惜予年之未央。", "悲不反余之所居兮，恨离予之故乡。", "鸟兽惊而失群兮，犹高飞而哀鸣。", "狐死必首丘兮，夫人孰能不反其真情？", "故人疏而日忘兮，新人近而俞好。", "莫能行于杳冥兮，孰能施于无报？", "苦众人之皆然兮，乘回风而远游。", "凌恆山其若陋兮，聊愉娱以忘忧。", "悲虚言之无实兮，苦众口之铄金。", "过故乡而一顾兮，泣歔欷而霑衿。", "厌白玉以为面兮，怀琬琰以为心。", "邪气入而感内兮，施玉色而外淫。", "何青云之流澜兮，微霜降之蒙蒙。", "徐风至而徘徊兮，疾风过之汤汤。", "闻南籓乐而欲往兮，至会稽而且止。", "见韩众而宿之兮，问天道之所在？", "借浮云以送予兮，载雌霓而为旌。"]'),
('chuci-35','哀命','东方朔','战国','楚辞','chuci','','[]','哀时命之不合兮，伤楚国之多忧。',302,'楚辞/chuci.json','["哀时命之不合兮，伤楚国之多忧。", "内怀情之洁白兮，遭乱世而离尤。", "恶耿介之直行兮，世溷浊而不知。", "何君臣之相失兮，上沅湘而分离。", "测汨罗之湘水兮，知时固而不反。", "伤离散之交乱兮，遂侧身而既远。", "处玄舍之幽门兮，穴岩石而窟伏。", "从水蛟而为徙兮，与神龙乎休息。", "何山石之崭岩兮，灵魂屈而偃蹇。", "含素水而蒙深兮，日眇眇而既远。", "哀形体之离解兮，神罔两而无舍。", "惟椒兰之不反兮，魂迷惑而不知路。", "愿无过之设行兮，虽灭没之自乐。", "痛楚国之流亡兮，哀灵修之过到。", "固时俗之溷浊兮，志瞀迷而不知路。", "念私门之正匠兮，遥涉江而远去。", "念女嬃之婵媛兮，涕泣流乎于悒。", "我决死而不生兮，虽重追吾何及。", "戏疾濑之素水兮，望高山之蹇产。", "哀高丘之赤岸兮，遂没身而不反。"]'),
('chuci-36','谬谏','东方朔','战国','楚辞','chuci','','[]','怨灵修之浩荡兮，夫何执操之不固？',364,'楚辞/chuci.json','["怨灵修之浩荡兮，夫何执操之不固？", "悲太山之为隍兮，孰江河之可涸？", "愿承闲而效志兮，恐犯忌而干讳。", "卒抚情以寂寞兮，然怊怅而自悲。", "玉与石其同匮兮，贯鱼眼与珠玑。", "驽骏杂而不分兮，服罢牛而骖骥。", "年滔滔而自远兮，寿冉冉而愈衰。", "心悇憛而烦冤兮，蹇超摇而无冀。", "固时俗之工巧兮，灭规矩而改错。", "郤骐骥而不乘兮，策驽骀而取路。", "当世岂无骐骥兮，诚无王良之善驭。", "见执辔者非其人兮，故驹跳而远去。", "不量凿而正枘兮，恐矩矱之不同。", "不论世而高举兮，恐操行之不调。", "弧弓弛而不张兮，孰云知其所至？", "无倾危之患难兮，焉知贤士之所死？", "俗推佞而进富兮，节行张而不著。", "贤良蔽而不群兮，朋曹比而党誉。", "邪说饰而多曲兮，正法弧而不公。", "直士隐而避匿兮，谗谀登乎明堂。", "弃彭咸之娱乐兮，灭巧倕之绳墨。", "菎蕗杂于黀蒸兮，机蓬矢以射革。", "驾蹇驴而无策兮，又何路之能极？", "以直鍼而为钓兮，又何鱼之能得？"]'),
('chuci-37','哀时命','庄忌','战国','楚辞','chuci','','[]','哀时命之不及古人兮，夫何予生之不遘时！',375,'楚辞/chuci.json','["哀时命之不及古人兮，夫何予生之不遘时！", "往者不可扳援兮，徠者不可与期。", "志憾恨而不逞兮，杼中情而属诗。", "夜炯炯而不寐兮，怀隐忧而历兹。", "心郁郁而无告兮，众孰可与深谋！", "欿愁悴而委惰兮，老冉冉而逮之。", "居处愁以隐约兮，志沉抑而不扬。", "道壅塞而不通兮，江河广而无梁。", "愿至昆仑之悬圃兮，采锺山之玉英。", "揽瑶木之橝枝兮，望阆风之板桐。", "弱水汩其为难兮，路中断而不通。", "势不能凌波以径度兮，又无羽翼而高翔。", "然隐悯而不达兮，独徙倚而彷徉。", "怅惝罔以永思兮，心纡轸而增伤。", "倚踌躇以淹留兮，日饥馑而绝粮。", "廓抱景而独倚兮，超永思乎故乡。", "廓落寂而无友兮，谁可与玩此遗芳？", "白日晼晼其將入兮，哀余寿之弗将。", "车既弊而马罢兮，蹇邅徊而不能行。", "身既不容于浊世兮，不知进退之宜当。", "冠崔嵬而切云兮，剑淋离而从横。", "衣摄叶以储与兮，左袪挂于榑桑", "右衽拂于不周兮，六合不足以肆行。", "上同凿枘于伏戏兮，下合矩矱于虞唐。"]'),
('chuci-38','匡机','王褒','战国','楚辞','chuci','','[]','极运兮不中，来将屈兮困穷。',137,'楚辞/chuci.json','["极运兮不中，来将屈兮困穷。", "余深愍兮惨怛，愿一列兮无从。", "乘日月兮上征，顾游心兮鄗酆。", "弥览兮九隅，彷徨兮兰宫。", "芷闾兮药房，奋摇兮众芳。", "菌阁兮蕙楼，观道兮从横。", "宝金兮委积，美玉兮盈堂。", "桂水兮潺湲，扬流兮洋洋。", "蓍蔡兮踊跃，孔鹤兮回翔。", "抚槛兮远望，念君兮不忘。", "怫郁兮莫陈，永怀兮内伤。"]'),
('chuci-39','通路','王褒','战国','楚辞','chuci','','[]','天门兮墬户，孰由兮贤者？',218,'楚辞/chuci.json','["天门兮墬户，孰由兮贤者？", "无正兮溷厕，怀德兮何睹？", "假寐兮愍斯，谁可与兮寤语？", "痛凤兮远逝，畜鴳兮近处。", "鲸鱏兮幽潜，从虾兮游陼。", "乘虬兮登阳，载象兮上行。", "朝发兮葱岭，夕至兮明光。", "北饮兮飞泉，南采兮芝英。", "宣游兮列宿，顺极兮彷徉。", "红采兮骍衣，翠缥兮为裳。", "舒佩兮綝纚，竦余剑兮干将。", "腾蛇兮后从，飞駏兮步旁。", "微观兮玄圃，览察兮瑶光。", "启匮兮探筴，悲命兮相当。", "纫蕙兮永辞，将离兮所思。", "浮云兮容与，道余兮何之？", "远望兮仟眠，闻雷兮阗阗。", "阴忧兮感余，惆怅兮自怜。"]'),
('chuci-40','危俊','王褒','战国','楚辞','chuci','','[]','林不容兮鸣蜩，余何留兮中州？',168,'楚辞/chuci.json','["林不容兮鸣蜩，余何留兮中州？", "陶嘉月兮总驾，搴玉英兮自修。", "结荣茝兮逶逝，将去烝兮远游。", "径岱土兮魏阙，历九曲兮牵牛。", "聊假日兮相佯，遗光燿兮周流。", "望太一兮淹息，纡余辔兮自休。", "晞白日兮皎皎，弥远路兮悠悠。", "顾列孛兮缥缥，观幽云兮陈浮。", "钜宝迁兮砏磤，雉咸雊兮相求。", "泱莽莽兮究志，惧吾心兮懤懤。", "步余马兮飞柱，览可与兮匹俦。", "卒莫有兮纤介，永余思兮怞怞。"]'),
('chuci-41','昭世','王褒','战国','楚辞','chuci','','[]','世溷兮冥昏，违君兮归真。',226,'楚辞/chuci.json','["世溷兮冥昏，违君兮归真。", "乘龙兮偃蹇，高回翔兮上臻。", "袭英衣兮缇[糹習]，披华裳兮芳芬。", "登羊角兮扶舆，浮云漠兮自娱。", "握神精兮雍容，与神人兮相胥。", "流星坠兮成雨，进瞵盼兮上丘墟。", "览旧邦兮滃郁，余安能兮久居。", "志怀逝兮心懰栗，纡余辔兮踌躇。", "闻素女兮微歌，听王后兮吹竽。", "魂悽怆兮感哀，肠回回兮盘纡。", "抚余佩兮缤纷，高太息兮自怜。", "使祝融兮先行，令昭明兮开门。", "驰六蛟兮上征，竦余驾兮入冥。", "历九州兮索合，谁可与兮终生。", "忽反顾兮西囿，睹轸丘兮崎倾。", "横垂涕兮泫流，悲余后兮失灵。"]'),
('chuci-42','尊嘉','王褒','战国','楚辞','chuci','','[]','季春兮阳阳，列草兮成行。',181,'楚辞/chuci.json','["季春兮阳阳，列草兮成行。", "余悲兮兰生，委积兮从横。", "江离兮遗捐，辛夷兮挤臧。", "伊思兮往古，亦多兮遭殃。", "伍胥兮浮江，屈子兮沉湘。", "运余兮念兹，心内兮怀伤。", "望淮兮沛沛，滨流兮则逝。", "榜舫兮下流，东注兮磕磕。", "蛟龙兮导引，文鱼兮上濑。", "抽蒲兮陈坐，援芙蕖兮为盖。", "水跃兮余旌，继以兮微蔡。", "云旗兮电骛，倏忽兮容裔。", "河伯兮开门，迎余兮欢欣。", "顾念兮旧都，怀恨兮艰难。", "窃哀兮浮萍，汎淫兮无根。"]'),
('chuci-43','蓄英','王褒','战国','楚辞','chuci','','[]','秋风兮萧萧，舒芳兮振条。',133,'楚辞/chuci.json','["秋风兮萧萧，舒芳兮振条。", "微霜兮眇眇，病殀兮鸣蜩。", "玄鸟兮辞归，飞翔兮灵丘。", "望谿谷兮滃郁，熊罴兮呴嗥。", "唐虞兮不存，何故兮久留？", "临渊兮汪洋，顾林兮忽荒。", "修余兮袿衣，骑霓兮南上。", "乘云兮回回，亹亹兮自强。", "将息兮兰皋，失志兮悠悠。", "蒶蕴兮霉黧，思君兮无聊。", "身去兮意存，怆恨兮怀愁。"]'),
('chuci-44','思忠','王褒','战国','楚辞','chuci','','[]','登九灵兮游神，静女歌兮微晨。',182,'楚辞/chuci.json','["登九灵兮游神，静女歌兮微晨。", "悲皇丘兮积葛，众体错兮交纷。", "贞枝抑兮枯槁，枉车登兮庆云。", "感余志兮惨栗，心怆怆兮自怜。", "驾玄螭兮北征，曏吾路兮葱岭。", "连五宿兮建旄，扬氛气兮为旌。", "历广漠兮驰骛，览中国兮冥冥。", "玄武步兮水母，与吾期兮南荣。", "登华盖兮乘阳，聊逍遥兮播光。", "抽库娄兮酌醴，援瓟瓜兮接粮。", "毕休息兮远逝，发玉軔兮西行。", "惟时俗兮疾正，弗可久兮此方。", "寤辟摽兮永思，心怫郁兮内伤。"]'),
('chuci-45','陶壅','王褒','战国','楚辞','chuci','','[]','览杳杳兮世惟，余惆怅兮何归。',210,'楚辞/chuci.json','["览杳杳兮世惟，余惆怅兮何归。", "伤时俗兮溷乱，将奋翼兮高飞。", "驾八龙兮连蜷，建虹旌兮威夷。", "观中宇兮浩浩，纷翼翼兮上跻。", "浮溺水兮舒光，淹低佪兮京沶。", "屯余车兮索友，睹皇公兮问师。", "道莫贵兮归真，羡余术兮可夷。", "吾乃逝兮南娭，道幽路兮九疑。", "越炎火兮万里，过万首兮嶷嶷。", "济江海兮蝉蜕，绝北梁兮永辞。", "浮云郁兮昼昏，霾土忽兮塺々。", "息阳城兮广夏，衰色罔兮中怠。", "意晓阳兮燎寤，乃自诊兮在兹。", "思尧舜兮袭兴，幸咎繇兮获谋。", "悲九州兮靡君，抚轼叹兮作诗。"]'),
('chuci-46','株昭','王褒','战国','楚辞','chuci','','[]','悲哉于嗟兮，心内切磋。',219,'楚辞/chuci.json','["悲哉于嗟兮，心内切磋。", "款冬而生兮，凋彼叶柯。", "瓦砾进宝兮，捐弃随和。", "铅刀厉御兮，顿弃太阿。", "骥垂两耳兮，中坂蹉跎。", "蹇驴服驾兮，无用日多。", "修洁处幽兮，贵宠沙劘。", "凤皇不翔兮，鹑鴳飞扬。", "乘虹骖蜺兮，载云变化。", "焦明开路兮，后属青蛇。", "步骤桂林兮，超骧卷阿。", "丘陵翔儛兮，谿谷悲歌。", "神章灵篇兮，赴曲相和。", "余私娱兹兮，孰哉复加。", "还顾世俗兮，坏败罔罗。", "卷佩将逝兮，涕流滂沲。", "乱曰：皇门开兮照下土，株秽除兮兰芷睹。", "四佞放兮後得禹，圣舜摄兮昭尧绪，孰能若兮原为辅。"]'),
('chuci-47','逢纷','刘向','战国','楚辞','chuci','','[]','伊伯庸之末胄兮，谅皇直之屈原。',370,'楚辞/chuci.json','["伊伯庸之末胄兮，谅皇直之屈原。", "云余肇祖于高阳兮，惟楚怀之婵连。", "原生受命于贞节兮，鸿永路有嘉名。", "齐名字于天地兮，并光明于列星。", "吸精粹而吐氛浊兮，横邪世而不取容。", "行叩诚而不阿兮，遂见排而逢谗。", "后听虚而黜实兮，不吾理而顺情。", "肠愤悁而含怒兮，志迁蹇而左倾。", "心戃慌其不我与兮，躬速速其不吾亲。", "辞灵修而陨志兮，吟泽畔之江滨。", "椒桂罗以颠覆兮，有竭信而归诚。", "谗夫蔼蔼而漫著兮，曷其不舒予情？", "始结言于庙堂兮，信中涂而叛之。", "怀兰蕙与衡芷兮，行中野而散之。", "声哀哀而怀高丘兮，心愁愁而思旧邦。", "愿承闲而自恃兮，径淫曀而道壅。", "颜霉黧以沮败兮，精越裂而衰耄。", "裳襜襜而含风兮，衣纳纳而掩露。", "赴江湘之湍流兮，顺波凑而下降。", "徐徘徊于山阿兮，飘风来之洶洶。", "驰余车兮玄石，步余马兮洞庭。", "平明发兮苍梧，夕投宿兮石城。", "芙蓉盖而菱华车兮，紫贝阙而玉堂。", "薜荔饰而陆离荐兮，鱼鳞衣而白蜺裳。"]'),
('chuci-48','离世','刘向','战国','楚辞','chuci','','[]','灵怀其不吾知兮，灵怀其不吾闻。',364,'楚辞/chuci.json','["灵怀其不吾知兮，灵怀其不吾闻。", "就灵怀之皇祖兮，愬灵怀之鬼神。", "灵怀曾不吾与兮，即听夫人之谀辞。", "余辞上参于天坠兮，旁引之于四时。", "指日月使延照兮，抚招摇以质正。", "立师旷俾端辞兮，命咎繇使并听。", "兆出名曰正则兮，卦发字曰灵均。", "余幼既有此鸿节兮，长愈固而弥纯。", "不从俗而诐行兮，直躬指而信志。", "不枉绳以追曲兮，屈情素以从事。", "端余行其如玉兮，述皇舆之踵迹。", "群阿容以晦光兮，皇舆覆以幽辟。", "舆中涂以回畔兮，驷马惊而横奔。", "执组者不能制兮，必折轭而摧辕。", "断镳衔以驰骛兮，暮去次而敢止。", "路荡荡其无人兮，遂不禦乎千里。", "身衡陷而下沉兮，不可获而复登。", "不顾身之卑贱兮，惜皇舆之不兴。", "出国门而端指兮，冀壹寤而锡还。", "哀仆夫之坎毒兮，屡离忧而逢患。", "九年之中不吾反兮，思彭咸之水游。", "惜师延之浮渚兮，赴汨罗之长流。", "遵江曲之逶移兮，触石碕而衡游。", "波澧澧而扬浇兮，顺长濑之浊流。"]'),
('chuci-49','怨思','刘向','战国','楚辞','chuci','','[]','惟郁郁之忧毒兮，志坎壈而不违。',361,'楚辞/chuci.json','["惟郁郁之忧毒兮，志坎壈而不违。", "身憔悴而考旦兮，日黄昏而长悲。", "闵空宇之孤子兮，哀枯杨之冤雏。", "孤雌吟于高墉兮，鸣鸠栖于桑榆。", "玄蝯失于潜林兮，独偏弃而远放。", "征夫劳于周行兮，处妇愤而长望。", "申诚信而罔违兮，情素洁于纽帛。", "光明齐于日月兮，文采耀燿于玉石。", "伤压次而不发兮，思沉抑而不扬。", "芳懿懿而终败兮，名靡散而不彰。", "背玉门以奔骛兮，蹇离尤而干诟。", "若龙逢之沉首兮，王子比干之逢醢。", "念社稷之几危兮，反为雠而见怨。", "思国家之离沮兮，躬获愆而结难。", "若青蝇之伪质兮，晋骊姬之反情。", "恐登阶之逢殆兮，故退伏于末庭。", "孽臣之号咷兮，本朝芜而不治。", "犯颜色而触谏兮，反蒙辜而被疑。", "菀蘼芜与菌若兮，渐藁本于洿渎。", "淹芳芷于腐井兮，弃鸡骇于筐簏。", "执棠谿以刜蓬兮，秉干将以割肉。", "筐泽泻以豹鞟兮，破荆和以继筑。", "时溷浊犹未清兮，世殽乱犹未察。", "欲容与以俟时兮，惧年岁之既晏。"]'),
('chuci-50','远逝','刘向','战国','楚辞','chuci','','[]','志隐隐而郁怫兮，愁独哀而冤结。',362,'楚辞/chuci.json','["志隐隐而郁怫兮，愁独哀而冤结。", "肠纷纭以缭转兮，涕渐渐其若屑。", "情慨慨而长怀兮，信上皇而质正。", "合五岳与八灵兮，讯九鬿与六神。", "指列宿以白情兮，诉五帝以置辞。", "北斗为我折中兮，太一为余听之。", "云服阴阳之正道兮，御后土之中和。", "佩苍龙之蚴虬兮，带隐虹之逶蛇。", "曳彗星之皓旰兮，抚朱爵与鵔鸃。", "游清灵之飒戾兮，服云衣之披披。", "杖玉策与朱旗兮，垂明月之玄珠。", "举霓旌之墆翳兮，建黄纁之总旄。", "躬纯粹而罔愆兮，承皇考之妙仪。", "惜往事之不合兮，横汨罗而下沥。", "乘隆波而南渡兮，逐江湘之顺流。", "赴阳侯之潢洋兮，下石濑而登洲。", "陆魁堆以蔽视兮，云冥冥而闇前。", "山峻高以无垠兮，遂曾闳而迫身。", "雪雰雰而薄木兮，云霏霏而陨集。", "阜隘狭而幽险兮，石嵾嵯以翳日。", "悲故乡而发忿兮，去余邦之弥久。", "背龙门而入河兮，登大坟而望夏首。", "横舟航而济湘兮，耳聊啾而戃慌。", "波淫淫而周流兮，鸿溶溢而滔荡。"]'),
('chuci-51','惜贤','刘向','战国','楚辞','chuci','','[]','览屈氏之离骚兮，心哀哀而怫郁。',361,'楚辞/chuci.json','["览屈氏之离骚兮，心哀哀而怫郁。", "声嗷嗷以寂寥兮，顾仆夫之憔悴。", "拨谄谀而匡邪兮，切淟涊之流俗。", "荡渨涹之奸咎兮，夷蠢蠢之溷浊。", "怀芬香而挟蕙兮，佩江蓠之婓婓。", "握申椒与杜若兮，冠浮云之峨峨。", "登长陵而四望兮，览芷圃之蠡蠡。", "游兰皋与蕙林兮，睨玉石之嵾嵯。", "扬精华以炫燿兮，芳郁渥而纯美。", "结桂树之旖旎兮，纫荃蕙与辛夷。", "芳若兹而不御兮，捐林薄而菀死。", "驱子侨之奔走兮，申徒狄之赴渊。", "若由夷之纯美兮，介子推之隐山。", "晋申生之离殃兮，荆和氏之泣血。", "吴申胥之抉眼兮，王子比干之横废。", "欲卑身而下体兮，心隐恻而不置。", "方圜殊而不合兮，钩绳用而异态。", "欲俟时于须臾兮，日阴曀其将暮。", "时迟迟其日进兮，年忽忽而日度。", "妄周容而入世兮，内距闭而不开。", "俟时风之清激兮，愈氛雾其如塺。", "进雄鸠之耿耿兮，谗介介而蔽之。", "默顺风以偃仰兮，尚由由而进之。", "心懭悢以冤结兮，情舛错以曼忧。"]'),
('chuci-52','忧苦','刘向','战国','楚辞','chuci','','[]','悲余心之悁悁兮，哀故邦之逢殃。',369,'楚辞/chuci.json','["悲余心之悁悁兮，哀故邦之逢殃。", "辞九年而不复兮，独茕茕而南行。", "思余俗之流风兮，心纷错而不受。", "遵野莽以呼风兮，步从容于山廋。", "巡陆夷之曲衍兮，幽空虚以寂寞。", "倚石岩以流涕兮，忧憔悴而无乐。", "登巑岏以长企兮，望南郢而闚之。", "山修远其辽辽兮，涂漫漫其无时。", "听玄鹤之晨鸣兮，于高冈之峨峨。", "独愤积而哀娱兮，翔江洲而安歌。", "三鸟飞以自南兮，览其志而欲北。", "原寄言于三鸟兮，去飘疾而不可得。", "欲迁志而改操兮，心纷结其未离。", "外彷徨而游览兮，内恻隐而含哀。", "聊须臾以时忘兮，心渐渐其烦错。", "原假簧以舒忧兮，志纡郁其难释。", "叹《离骚》以扬意兮，犹未殫于《九章》。", "长嘘吸以于悒兮，涕横集而成行。", "伤明珠之赴泥兮，鱼眼玑之坚藏。", "同驽骡与乘駔兮，杂斑駮与阘茸。", "葛藟虆于桂树兮，鸱鸮集于木兰。", "偓促谈于廊庙兮，律魁放乎山间。", "恶虞氏之箫《韶》兮，好遗风之《激楚》。", "潜周鼎于江淮兮，爨土鬵于中宇。"]'),
('chuci-53','愍命','刘向','战国','楚辞','chuci','','[]','昔皇考之嘉志兮，喜登能而亮贤。',370,'楚辞/chuci.json','["昔皇考之嘉志兮，喜登能而亮贤。", "情纯洁而罔薉兮，姿盛质而无愆。", "放佞人与谄谀兮，斥谗夫与便嬖。", "亲忠正之悃诚兮，招贞良与明智。", "心溶溶其不可量兮，情澹澹其若渊。", "回邪辟而不能入兮，诚原藏而不可迁。", "逐下袟于後堂兮，迎虙妃于伊雒。", "刜谗贼于中廇兮，选吕管于榛薄。", "丛林之下无怨士兮，江河之畔无隐夫。", "三苗之徒以放逐兮，伊皋之伦以充庐。", "今反表以为里兮，颠裳以为衣。", "戚宋万于两楹兮，废周邵于遐夷。", "却骐骥以转运兮，腾驴骡以驰逐。", "蔡女黜而出帷兮，戎妇入而綵绣服。", "庆忌囚于阱室兮，陈不占战而赴围。", "破伯牙之号钟兮，挟人筝而弹纬。", "藏瑉石于金匮兮，捐赤瑾于中庭。", "韩信蒙于介胄兮，行夫将而攻城。", "莞芎弃于泽洲兮，瓟瓥蠹于筐簏。", "麒麟奔于九皋兮，熊罴群而逸囿。", "折芳枝与琼华兮，树枳棘与薪柴。", "掘荃蕙与射干兮，耘藜藿与蘘荷。", "惜今世其何殊兮，远近思而不同。", "或沉沦其无所达兮，或清激其无所通。"]'),
('chuci-54','思古','刘向','战国','楚辞','chuci','','[]','冥冥深林兮，树木郁郁。',358,'楚辞/chuci.json','["冥冥深林兮，树木郁郁。", "山参差以崭岩兮，阜杳杳以蔽日。", "悲余心之悁悁兮，目眇眇而遗泣。", "风骚屑以摇木兮，云吸吸以湫戾。", "悲余生之无欢兮，愁倥傯于山陆。", "旦徘徊于长阪兮，夕彷徨而独宿。", "发披披以鬤鬤兮，躬劬劳而瘏悴。", "魂俇俇而南行兮，泣霑襟而濡袂。", "心婵媛而无告兮，口噤闭而不言。", "违郢都之旧闾兮，回湘、沅而远迁。", "念余邦之横陷兮，宗鬼神之无次。", "闵先嗣之中绝兮，心惶惑而自悲。", "聊浮游于山陿兮，步周流于江畔。", "临深水而长啸兮，且倘佯而氾观。", "兴离骚之微文兮，冀灵修之壹悟。", "还余车于南郢兮，复往轨于初古。", "道修远其难迁兮，伤余心之不能已。", "背三五之典刑兮，绝洪范之辟纪。", "播规矩以背度兮，错权衡而任意。", "操绳墨而放弃兮，倾容幸而侍侧。", "甘棠枯于丰草兮，藜棘树于中庭。", "西施斥于北宫兮，仳倠倚于弥楹。", "乌获戚而骖乘兮，燕公操于马圉。", "蒯聩登于清府兮，咎繇弃而在野。"]'),
('chuci-55','远游','刘向','战国','楚辞','chuci','','[]','悲余性之不可改兮，屡惩艾而不迻。',364,'楚辞/chuci.json','["悲余性之不可改兮，屡惩艾而不迻。", "服觉皓以殊俗兮，貌揭揭以巍巍。", "譬若王侨之乘云兮，载赤霄而凌太清。", "欲与天地参寿兮，与日月而比荣。", "登昆仑而北首兮，悉灵圉而来谒。", "选鬼神于太阴兮，登阊阖于玄阙。", "回朕车俾西引兮，褰虹旗于玉门。", "驰六龙于三危兮，朝西灵于九滨。", "结余轸于西山兮，横飞谷以南征。", "绝都广以直指兮，历祝融于硃冥。", "枉玉衡于炎火兮，委两馆于咸唐。", "贯澒濛以东朅兮，维六龙于扶桑。", "周流览于四海兮，志升降以高驰。", "徵九神于回极兮，建虹采以招指。", "驾鸾凤以上游兮，从玄鹤与鹪明。", "孔鸟飞而送迎兮，腾群鹤于瑶光。", "排帝宫与罗囿兮，升县圃以眩灭。", "结琼枝以杂佩兮，立长庚以继日。", "凌惊雷以轶骇电兮，缀鬼谷于北辰。", "鞭风伯使先驱兮，囚灵玄于虞渊。", "遡高风以低佪兮，览周流于朔方。", "就颛顼而敶辞兮，考玄冥于空桑。", "旋车逝于崇山兮，奏虞舜于苍梧。", "济杨舟于会稽兮，就申胥于五湖。"]'),
('chuci-56','逢尤','王逸','战国','楚辞','chuci','','[]','悲兮愁，哀兮忧！',280,'楚辞/chuci.json','["悲兮愁，哀兮忧！", "天生我兮当闇时，被诼谮兮虚获尤。", "心烦憒兮意无聊，严载驾兮出戏游。", "周八极兮历九州，求轩辕兮索重华。", "世既卓兮远眇眇，握佩玖兮中路躇。", "羡咎繇兮建典谟，懿风后兮受瑞图。", "愍余命兮遭六极，委玉质兮於泥涂。", "遽傽遑兮驱林泽，步屏营兮行丘阿。", "车軏折兮马虺颓，惷怅立兮涕滂沱。", "思丁文兮圣明哲，哀平差兮迷谬愚。", "吕傅举兮殷周兴，忌嚭专兮郢吴虚。", "仰长叹兮气噎结，悒殟绝兮咶复苏。", "虎兕争兮於廷中，豺狼斗兮我之隅。", "云雾会兮日冥晦，飘风起兮扬尘埃。", "走鬯罔兮乍东西，欲窜伏兮其焉如？", "念灵闺兮隩重深，原竭节兮隔无由。", "望旧邦兮路逶随，忧心悄兮志勤劬。", "魂茕茕兮不遑寐，目眽眽兮寤终朝。"]'),
('chuci-57','怨上','王逸','战国','楚辞','chuci','','[]','令尹兮謷謷，群司兮譨譨。',253,'楚辞/chuci.json','["令尹兮謷謷，群司兮譨譨。", "哀哉兮淈淈，上下兮同流。", "菽藟兮蔓衍，芳虈兮挫枯。", "硃紫兮杂乱，曾莫兮别诸。", "倚此兮岩穴，永思兮窈悠。", "嗟怀兮眩惑，用志兮不昭。", "将丧兮玉斗，遗失兮钮枢。", "我心兮煎熬，惟是兮用忧。", "进恶兮九旬，复顾兮彭务。", "拟斯兮二踪，未知兮所投。", "谣吟兮中野，上察兮璇玑。", "大火兮西睨，摄提兮运低。", "雷霆兮硠磕，雹霰兮霏霏。", "奔电兮光晃，凉风兮怆悽。", "鸟兽兮惊骇，相从兮宿栖。", "鸳鸯兮噰噰，狐狸兮徾徾。", "哀吾兮介特，独处兮罔依。", "蝼蛄兮鸣东，蟊蠽兮号西。", "蛓缘兮我裳，蠋入兮我怀。", "虫豸兮夹余，惆怅兮自悲。", "伫立兮忉怛，心结縎兮折摧。"]'),
('chuci-58','疾世','王逸','战国','楚辞','chuci','','[]','周徘徊兮汉渚，求水神兮灵女。',280,'楚辞/chuci.json','["周徘徊兮汉渚，求水神兮灵女。", "嗟此国兮无良，媒女诎兮謰謱。", "鴳雀列兮譁讙，鸲鹆鸣兮聒余。", "抱昭华兮宝璋，欲衒鬻兮莫取。", "言旋迈兮北徂，叫我友兮配耦。", "日阴曀兮未光，阒睄窕兮靡睹。", "纷载驱兮高驰，将谘询兮皇羲。", "遵河皋兮周流，路变易兮时乖。", "濿沧海兮东游，沐盥浴兮天池。", "访太昊兮道要，云靡贵兮仁义。", "志欣乐兮反征，就周文兮邠歧。", "秉玉英兮结誓，日欲暮兮心悲。", "惟天禄兮不再，背我信兮自违。", "逾陇堆兮渡漠，过桂车兮合黎。", "赴昆山兮馽騄，从邛遨兮栖迟。", "吮玉液兮止渴，齧芝华兮疗饥。", "居嵺廓兮尠畴，远梁昌兮几迷。", "望江汉兮濩渃，心紧絭兮伤怀。", "时昢昢兮且旦，尘莫莫兮未晞。", "忧不暇兮寝食，吒增叹兮如雷。"]'),
('chuci-59','悯上','王逸','战国','楚辞','chuci','','[]','哀世兮睩睩，諓諓兮嗌喔。',249,'楚辞/chuci.json','["哀世兮睩睩，諓諓兮嗌喔。", "众多兮阿媚，骪靡兮成俗。", "贪枉兮党比，贞良兮茕独。", "鹄窜兮枳棘，鹈集兮帷幄。", "罽蕠兮青葱，槁本兮萎落。", "睹斯兮伪惑，心为兮隔错。", "逡巡兮圃薮，率彼兮畛陌。", "川谷兮渊渊，山阜兮峉峉。", "丛林兮崟崟，株榛兮岳岳。", "霜雪兮漼溰，冰冻兮洛泽。", "东西兮南北，罔所兮归薄。", "庇廕兮枯树，匍匐兮岩石。", "蜷跼兮寒局数，独处兮志不申。", "年齿尽兮命迫促，魁垒挤摧兮常困辱。", "含忧强老兮愁无乐，须发苎悴兮顠鬓白。", "思灵泽兮一膏沐，怀兰英兮把琼若，待天明兮立踯躅。", "云蒙蒙兮电鯈烁，孤雌惊兮鸣呴呴。", "思怫郁兮肝切剥，忿悁悒兮孰诉告。"]'),
('chuci-60','遭厄','王逸','战国','楚辞','chuci','','[]','悼屈子兮遭厄，沉王躬兮湘汨。',238,'楚辞/chuci.json','["悼屈子兮遭厄，沉王躬兮湘汨。", "何楚国兮难化，迄于今兮不易。", "士莫志兮羔裘，竞佞谀兮谗阋。", "指正义兮为曲，訿玉璧兮为石。", "殦雕游兮华屋，鵔鸃栖兮柴蔟。", "起奋迅兮奔走，违群小兮謑訽。", "载青云兮上昇，適昭明兮所处。", "蹑天衢兮长驱，踵九阳兮戏荡。", "越云汉兮南济，秣余马兮河鼓。", "云霓纷兮晻翳，参辰回兮颠倒。", "逢流星兮问路，顾我指兮从左。", "俓娵觜兮直驰，御者迷兮失轨。", "遂踢达兮邪造，与日月兮殊道。", "志阏绝兮安如，哀所求兮不耦。", "攀天阶兮下视，见鄢郢兮旧宇。", "意逍遥兮欲归，众秽盛兮沓沓。", "思哽饐兮诘诎，涕流澜兮如雨。"]'),
('chuci-61','悼乱','王逸','战国','楚辞','chuci','','[]','嗟嗟兮悲夫，殽乱兮纷挐。',252,'楚辞/chuci.json','["嗟嗟兮悲夫，殽乱兮纷挐。", "茅丝兮同综，冠屦兮共絇。", "督万兮侍宴，周邵兮负刍。", "白龙兮见射，灵龟兮执拘。", "仲尼兮困厄，邹衍兮幽囚。", "伊余兮念兹，奔遁兮隐居。", "将升兮高山，上有兮猴猿。", "欲入兮深谷，下有兮虺蛇。", "左见兮鸣鵙，右睹兮呼枭。", "惶悸兮失气，踊跃兮距跳。", "便旋兮中原，仰天兮增叹。", "菅蒯兮楙莽，雚苇兮仟眠。", "鹿蹊兮躖躖，貒貉兮蟫蟫。", "鹯鹞兮轩轩，鹑鹌兮甄甄。", "哀我兮寡独，靡有兮齐伦。", "意欲兮沉吟，迫日兮黄昏。", "玄鹤兮高飞，曾逝兮青冥。", "鶬鶊兮喈喈，山鹊兮嚶嚶。", "鸿鸬兮振翅，归雁兮于征。", "吾志兮觉悟，怀我兮圣京。", "垂屣兮将起，跓俟兮硕明。"]'),
('chuci-62','伤时','王逸','战国','楚辞','chuci','','[]','惟昊天兮昭灵，阳气发兮清明。',308,'楚辞/chuci.json','["惟昊天兮昭灵，阳气发兮清明。", "风習習兮和暖，百草萌兮华荣。", "堇荼茂兮扶疏，蘅芷彫兮莹嫇。", "愍贞良兮遇害，将夭折兮碎糜。", "时混混兮浇饡，哀当世兮莫知。", "览往昔兮俊彦，亦诎辱兮系纍。", "管束缚兮桎梏，百贸易兮传卖。", "遭桓缪兮识举，才德用兮列施。", "且从容兮自慰，玩琴书兮游戏。", "迫中国兮迮陿，吾欲之兮九夷。", "超五岭兮嵯峨，观浮石兮崔嵬。", "陟丹山兮炎野，屯余车兮黄支。", "就祝融兮稽疑，嘉己行兮无为。", "乃回朅兮北逝，遇神孈兮宴娭。", "欲静居兮自娱，心愁慼兮不能。", "放余辔兮策驷，忽飙腾兮浮云。", "蹠飞杭兮越海，从安期兮蓬莱。", "缘天梯兮北上，登太一兮玉台。", "使素女兮鼓簧，乘戈和兮讴谣。", "声噭誂兮清和，音晏衍兮要婬。", "咸欣欣兮酣乐，余眷眷兮独悲。", "顾章华兮太息，志恋恋兮依依。"]'),
('chuci-63','哀岁','王逸','战国','楚辞','chuci','','[]','旻天兮清凉，玄气兮高朗。',279,'楚辞/chuci.json','["旻天兮清凉，玄气兮高朗。", "北风兮潦洌，草木兮苍唐。", "蛜蚗兮噍噍，蝍蛆兮穰穰。", "岁忽忽兮惟暮，余感时兮悽怆。", "伤俗兮泥浊，矇蔽兮不章。", "宝彼兮沙砾，捐此兮夜光。", "椒瑛兮湟汙，葈耳兮充房。", "摄衣兮缓带，操我兮墨阳。", "昇车兮命仆，将驰兮四荒。", "下堂兮见虿，出门兮触螽。", "巷有兮蚰蜓，邑多兮螳螂。", "睹斯兮嫉贼，心为兮切伤。", "俛念兮子胥，仰怜兮比干。", "投剑兮脱冕，龙屈兮蜿蟤。", "潜藏兮山泽，匍匐兮丛攒。", "窥见兮溪涧，流水兮沄沄。", "鼋鼍兮欣欣，鱣鲇兮延延。", "群行兮上下，骈罗兮列陈。", "自恨兮无友，特处兮茕茕。", "冬夜兮陶陶，雨雪兮冥冥。", "神光兮颎颎，鬼火兮荧荧。", "修德兮困控，愁不聊兮遑生。", "忧纡兮郁郁，恶所兮写情。"]'),
('chuci-64','守志','王逸','战国','楚辞','chuci','','[]','陟玉峦兮逍遥，览高冈兮峣峣。',331,'楚辞/chuci.json','["陟玉峦兮逍遥，览高冈兮峣峣。", "桂树列兮纷敷，吐紫华兮布条。", "实孔鸾兮所居，今其集兮惟鸮。", "乌鹊惊兮哑哑，余顾盼兮怊怊。", "彼日月兮闇昧，障覆天兮祲氛。", "伊我后兮不聪，焉陈诚兮效忠。", "摅羽翮兮超俗，游陶遨兮养神。", "乘六蛟兮蜿蝉，遂驰骋兮升云。", "扬彗光兮为旗，秉电策兮为鞭。", "朝晨发兮鄢郢，食时至兮增泉。", "绕曲阿兮北次，造我车兮南端。", "谒玄黄兮纳贽，崇忠贞兮弥坚。", "历九宫兮遍观，睹秘藏兮宝珍。", "就传说兮骑龙，与织女兮合婚。", "举天罼兮掩邪，彀天弧兮射奸。", "随真人兮翱翔，食元气兮长存。", "望太微兮穆穆，睨三阶兮炳分。", "相辅政兮成化，建烈业兮垂勋。", "目瞥瞥兮西没，道遐回兮阻叹。", "志稸积兮未通，怅敞罔兮自怜。", "乱曰：", "天庭明兮云霓藏，三光朗兮镜万方。", "斥蜥蜴兮进龟龙，策谋从兮翼机衡。", "配稷契兮恢唐功，嗟英俊兮未为双。"]');
